import React, { useEffect } from 'react';
import './Home.css';
import tshirt from '../tshirt.webp';
import shirt from '../shirt.webp';
import pant from '../pant.webp';
import logo from '../assets/w-banner.jpg';
import Slider from 'react-slick';
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

// 🔹 Import AOS (Animate on Scroll)
import AOS from "aos";
import "aos/dist/aos.css";

function Home() {
  const bannerImages = [
    "/images/Banner4.jpg",
    "/images/Banner2.jpg",
    "/images/Banner3.jpg"
  ];

  const settings = {
    dots: true,
    infinite: true,
    autoplay: true,
    autoplaySpeed: 2000,
    arrows: false,
    slidesToShow: 1,
    slidesToScroll: 1
  };

  // 🔹 Initialize AOS
  useEffect(() => {
    AOS.init({
      duration: 1000, // animation speed (1s)
      once: true,     // animation only once
      offset: 100,    // start animation after 100px scroll
    });
  }, []);

  return (
    <div className="home-container">

      {/* 🔁 Hero Banner Section */}
      <div className="hero-banner" data-aos="fade-up">
        <Slider {...settings}>
          {bannerImages.map((img, index) => (
            <div key={index}>
              <img src={img} alt={`Banner ${index}`} className="banner-img" />
            </div>
          ))}
        </Slider>
      </div>

      {/* 🛍️ Featured Products */}
      <section className="products-section" data-aos="fade-up">
        <h2 className='hd'>🛍️ Featured Products</h2>
        <div className="product-list">
          <div className="product-card" data-aos="zoom-in" data-aos-delay="100">
            <img src={tshirt} alt="T-Shirt" />
            <h3>Cool T-Shirt</h3>
            <p>₹499</p>
          </div>
          <div className="product-card" data-aos="zoom-in" data-aos-delay="200">
            <img src={shirt} alt="Dress" />
            <h3>Stylish Dress</h3>
            <p>₹999</p>
          </div>
          <div className="product-card" data-aos="zoom-in" data-aos-delay="300">
            <img src={pant} alt="Jeans" />
            <h3>Classic Jeans</h3>
            <p>₹799</p>
          </div>
        </div>
      </section>

      {/* 🌿 Pure Cotton Quality Section */}
      <section className="cotton-quality" data-aos="fade-right">
        <div className="cotton-content">
          <img src="/images/cotton.png" alt="Pure Cotton" className="cotton-img" data-aos="zoom-in" />
          <div className="cotton-text" data-aos="fade-left">
            <h2>🌿 100% Pure Cotton</h2>
            <p>
              Experience the comfort of <strong>premium cotton</strong>.
              Our fabrics are <em>soft, breathable, and eco-friendly</em> –
              perfect for every season.
            </p>
            <p>✅ Skin Friendly | ✅ Long Lasting | ✅ Sustainable</p>
          </div>
        </div>
      </section>

      {/* 🔐 Login / Sign Up Buttons Section */}
      <section className="home-auth-buttons" data-aos="fade-up">
        <h2 className="hd">🔐 Access Your Account</h2>
        <div className="button-group">
          <a href="/login" className="auth-link-btn" data-aos="flip-left">Login</a>
          <a href="/signup" className="auth-link-btn" data-aos="flip-right">Sign Up</a>
        </div>
      </section>

      {/* 🏢 Franchise Enquiry Banner (WhatsApp Style) */}
      <section className="franchise-banner" data-aos="zoom-in">
        <h2>💼 Franchise Enquiry</h2>
        <p>Start your own clothing franchise with us and grow together!</p>
        <a
          href="https://wa.me/919990343478?text=Hi%20I%20am%20interested%20in%20franchise%20enquiry"
          target="_blank"
          rel="noopener noreferrer"
          className="franchise-btn"
          data-aos="pulse"
          data-aos-delay="200"
        >
          💬 Enquire Now on WhatsApp
        </a>
      </section>

    </div>
  );
}

export default Home;
